    @Test
    void testOptionsWhitespaceNormalized() throws Exception {
        // Normalized whitespace mode collapses multiple spaces
        var options = ConversionOptions.builder().withWhitespaceMode("Normalized").build();
        var result = HtmlToMarkdownRs.convert("<p>Text   with    extra   spaces.</p>", options);
        assertFalse(java.util.Optional.ofNullable(result.content()).isEmpty(), "expected non-empty value");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("Text"), "expected to contain: " + "Text");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("with"), "expected to contain: " + "with");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("extra"), "expected to contain: " + "extra");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("spaces."), "expected to contain: " + "spaces.");
    }

    @Test
    void testOptionsWhitespaceStrict() throws Exception {
        // Strict whitespace mode preserves whitespace as-is
        var options = ConversionOptions.builder().withWhitespaceMode("Strict").build();
        var result = HtmlToMarkdownRs.convert("<p>Preserved   spacing.</p>", options);
        assertFalse(java.util.Optional.ofNullable(result.content()).isEmpty(), "expected non-empty value");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("Preserved"), "expected to contain: " + "Preserved");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("spacing."), "expected to contain: " + "spacing.");
    }

    @Test
    void testOptionsWrapDisabled() throws Exception {
        // Wrap option disabled preserves long lines without breaking
        var options = ConversionOptions.builder().withWrap(false).build();
        var result = HtmlToMarkdownRs.convert("<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", options);
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("This is a long paragraph that should not be wrapped at all because wrapping is disabled."), "expected to contain: " + "This is a long paragraph that should not be wrapped at all because wrapping is disabled.");
    }

    @Test
    void testOptionsWrapEnabled() throws Exception {
        // Wrap option enabled with custom width wraps long lines
        var options = ConversionOptions.builder().withWrap(true).withWrapWidth(Optional.of(40L)).build();
        var result = HtmlToMarkdownRs.convert("<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", options);
        assertFalse(java.util.Optional.ofNullable(result.content()).isEmpty(), "expected non-empty value");
        assertTrue(java.util.Optional.ofNullable(result.content()).orElse("").contains("This is a long paragraph"), "expected to contain: " + "This is a long paragraph");
    }

